import{_ as o,o as a,c as t,a3 as r}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":1784665499000}'),s={name:"faq.md"};function n(i,e,h,l,p,d){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-is-a-workspace-in-notely" tabindex="-1">What is a workspace in Notely? <a class="header-anchor" href="#what-is-a-workspace-in-notely" aria-label="Permalink to &quot;What is a workspace in Notely?&quot;">​</a></h2><p>A workspace is the folder you open with <strong>File -&gt; Open Workspace</strong>. It holds your notes, files, and Notely&#39;s support data for that set of notes.</p><h2 id="where-does-notely-store-my-data" tabindex="-1">Where does Notely store my data? <a class="header-anchor" href="#where-does-notely-store-my-data" aria-label="Permalink to &quot;Where does Notely store my data?&quot;">​</a></h2><p>Your notes stay in the workspace folder you choose.</p><p>Notely also keeps a <code>.notes-app/</code> folder there for note history and other support data.</p><p>Some app-wide preferences, like recent workspaces and theme choice, are stored separately by the app.</p><h2 id="does-notely-work-offline" tabindex="-1">Does Notely work offline? <a class="header-anchor" href="#does-notely-work-offline" aria-label="Permalink to &quot;Does Notely work offline?&quot;">​</a></h2><p>Yes for core note-taking features.</p><p>You can create notes, edit them, preview them, manage media, review history, use the terminal, and export workspaces offline.</p><h2 id="which-features-require-internet" tabindex="-1">Which features require internet? <a class="header-anchor" href="#which-features-require-internet" aria-label="Permalink to &quot;Which features require internet?&quot;">​</a></h2><p>AI features need internet access and a working account or key for the service you chose.</p><p>Device-to-device sync usually only needs both devices to reach each other on the same network.</p><h2 id="what-is-notes-app" tabindex="-1">What is <code>.notes-app</code>? <a class="header-anchor" href="#what-is-notes-app" aria-label="Permalink to &quot;What is `.notes-app`?&quot;">​</a></h2><p><code>.notes-app</code> is Notely&#39;s own support folder for things like note history, image notes, and other behind-the-scenes app data.</p><h2 id="should-notes-app-be-committed-to-git" tabindex="-1">Should <code>.notes-app</code> be committed to Git? <a class="header-anchor" href="#should-notes-app-be-committed-to-git" aria-label="Permalink to &quot;Should `.notes-app` be committed to Git?&quot;">​</a></h2><p>Usually no.</p><p>If your workspace is a Git folder, Notely can help keep <code>.notes-app/</code> out of version control so private app files do not end up in project history.</p><h2 id="can-i-restore-deleted-or-changed-notes" tabindex="-1">Can I restore deleted or changed notes? <a class="header-anchor" href="#can-i-restore-deleted-or-changed-notes" aria-label="Permalink to &quot;Can I restore deleted or changed notes?&quot;">​</a></h2><p>Yes.</p><p>Use <strong>File -&gt; Versions</strong> to inspect and restore earlier versions of a note. Notes and folders moved out of the main workspace flow are also handled by Notely&#39;s removed-folder flow.</p><h2 id="how-do-i-reopen-a-workspace-quickly" tabindex="-1">How do I reopen a workspace quickly? <a class="header-anchor" href="#how-do-i-reopen-a-workspace-quickly" aria-label="Permalink to &quot;How do I reopen a workspace quickly?&quot;">​</a></h2><p>Use <strong>File -&gt; Open Recent</strong> or the command palette entry for recent workspaces.</p><h2 id="does-notely-have-a-plugin-system" tabindex="-1">Does Notely have a plugin system? <a class="header-anchor" href="#does-notely-have-a-plugin-system" aria-label="Permalink to &quot;Does Notely have a plugin system?&quot;">​</a></h2><p>Not currently. The app does not expose a user plugin or extension mechanism.</p><h2 id="what-happens-if-i-configure-ai" tabindex="-1">What happens if I configure AI? <a class="header-anchor" href="#what-happens-if-i-configure-ai" aria-label="Permalink to &quot;What happens if I configure AI?&quot;">​</a></h2><p>AI requests only run when you use an AI feature. They go to the service you set up in <strong>AI -&gt; AI Settings</strong>.</p><p>The app keeps its AI working data on your device unless you explicitly move or export it.</p><h2 id="what-is-the-easiest-way-to-learn-shortcuts" tabindex="-1">What is the easiest way to learn shortcuts? <a class="header-anchor" href="#what-is-the-easiest-way-to-learn-shortcuts" aria-label="Permalink to &quot;What is the easiest way to learn shortcuts?&quot;">​</a></h2><p>Open <strong>Help -&gt; Keyboard Shortcuts</strong> (<code>Ctrl/Cmd + /</code>). The in-app guide lists current global, editor, landing, and preview shortcuts.</p>',30)])])}const f=o(s,[["render",n]]);export{u as __pageData,f as default};
